/* Auto-generated 128x64 splash bitmap for the SESSION LOADING screen.
 * 1 bit per pixel, MSB-first, row-major. 16 bytes per row × 64 rows = 1024 bytes.
 * Source: Downloads/Untitled - May 20, 2026 at 14.49.53.bmp (24bpp BMP, thresholded at lum>=128). */
const HEX = '';
export const SPLASH_W = 128;
export const SPLASH_H = 64;
/* Decoded once at module load. Uint8Array of 1024 bytes. */
export const SPLASH_BITS = (function() {
    const arr = new Uint8Array(1024);
    for (let i = 0; i < 1024; i++)
        arr[i] = parseInt(HEX.substr(i * 2, 2), 16);
    return arr;
})();
